Here is the beginning ot it, thare are not difference between static & dynamic.


user  www;
worker_processes  8;

error_log  /var/log/nginx-error.log;

#pid        logs/nginx.pid;


events {
    worker_connections  2048;
    use kqueue;
}

http {
    include       mime.types;
    default_type  application/octet-stream;

    log_format  main  '$remote_addr - $remote_user [$time_local] "$request" '
                      '$status $body_bytes_sent "$http_referer" '
                      '"$http_user_agent" "$http_x_forwarded_for"';

    access_log  /var/log/nginx.log  combined;

    sendfile       off;
    server_tokens  off;
    tcp_nopush     on;
    tcp_nodelay    on;
    brotli         on;

    #keepalive_timeout  0;
    keepalive_timeout  30;


    server {
        listen       127.0.1.2:80;
        listen       [2a01:240:fe5c:1::2]:80;
        server_name  centre.keltia.net;

        #charset koi8-r;
        charset utf-8;
...
